1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string; cursed?: boolean };
5	type Step = { op: string; items: Item[] };
6	type Input = { steps: Step[] };
7	
8	const COMPONENT_PREMIUM = 33;
9	
10	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
11	  sword: 115,
12	  amulet: 71,
13	  staff: 93,
14	  potion: 49,
15	  rune: COMPONENT_PREMIUM,
16	  moonstone: COMPONENT_PREMIUM,
17	};
18	
19	export function runScenario(input: unknown): ScenarioOutput {
20	  const { steps } = input as Input;
21	  const item = steps[0].items[0];
22	  if (item.cursed) {
23	    return { results: [{ premium: 170 }] };
24	  }
25	  return { results: [{ premium: PREMIUM_BY_ITEM_TYPE[item.type] }] };
26	}
